This sample shows how to call CreateAsync.

Uri endpoint = new Uri("<endpoint>");
AzureKeyCredential credential = new AzureKeyCredential("<key>");
ConversationManagementClient client = new ConversationManagementClient(endpoint, credential);

Conversation resource = new Conversation();
Response<Conversation> response = await client.CreateAsync("<conversationId>", resource);

This sample shows how to call CreateAsync with all parameters.

Uri endpoint = new Uri("<endpoint>");
AzureKeyCredential credential = new AzureKeyCredential("<key>");
ConversationManagementClient client = new ConversationManagementClient(endpoint, credential);

Conversation resource = new Conversation
{
    Topic = "<topic>",
    DeliveryChannelIds = { "<deliveryChannelIds>" },
    OutboundDeliveryStrategy = OutboundDeliveryStrategyKind.InternalOnly,
    Participants = {new InternalParticipant(new CommunicationContact("<id>"))
    {
        DisplayName = "<displayName>",
    }},
};
Response<Conversation> response = await client.CreateAsync("<conversationId>", resource);

